import React, { useEffect, useMemo, useState } from 'react';
import { View, Text, Button, StyleSheet, FlatList, TouchableOpacity } from 'react-native';

const TOKEN_PREFIX = 'local';
const TOKEN_LENGTH = 32;

const generateRandomToken = () => {
  const chars = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
  let token = `${TOKEN_PREFIX}_`;
  for (let i = 0; i < TOKEN_LENGTH; i += 1) {
    token += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return token;
};

const generateTokenMetadata = () => ({
  id: `${Date.now()}_${Math.random().toString(36).slice(2)}`,
  token: generateRandomToken(),
  createdAt: new Date().toISOString(),
  synced: false,
});

export default function OfflineTokenGenerator() {
  const [isOnline, setIsOnline] = useState(true);
  const [tokens, setTokens] = useState([]);

  useEffect(() => {
    const timer = setInterval(() => {
      const nextOnlineState = Math.random() > 0.5;
      setIsOnline(nextOnlineState);
    }, 5000);

    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (!isOnline) {
      const newToken = generateTokenMetadata();
      setTokens(prev => [newToken, ...prev].slice(0, 20));
    }
  }, [isOnline]);

  const statusText = useMemo(() => (isOnline ? 'Online' : 'Offline - generating local session token'), [isOnline]);

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Offline Token Generator</Text>
      <Text style={[styles.status, isOnline ? styles.online : styles.offline]}>{statusText}</Text>

      <View style={styles.actions}>
        <Button
          title="Generate Token"
          onPress={() => {
            const newToken = generateTokenMetadata();
            setTokens(prev => [newToken, ...prev].slice(0, 20));
          }}
        />
        <View style={styles.spacer} />
        <Button
          title={isOnline ? 'Set Offline' : 'Set Online'}
          onPress={() => setIsOnline(prev => !prev)}
        />
      </View>

      <FlatList
        data={tokens}
        keyExtractor={item => item.id}
        renderItem={({ item }) => (
          <View style={styles.tokenCard}>
            <Text style={styles.tokenLabel}>Token</Text>
            <Text style={styles.tokenValue}>{item.token}</Text>
            <Text style={styles.tokenMeta}>Created: {item.createdAt}</Text>
            <Text style={styles.tokenMeta}>Status: {item.synced ? 'Synced' : 'Local only'}</Text>
          </View>
        )}
        ListEmptyComponent={
          <View style={styles.empty}>
            <Text style={styles.emptyText}>No tokens generated yet.</Text>
          </View>
        }
      />

      <TouchableOpacity
        style={styles.clearButton}
        onPress={() => setTokens([])}
      >
        <Text style={styles.clearButtonText}>Clear Tokens</Text>
      </TouchableOpacity>
    </View>
  );
}

